class Solution:
    def longestPalindrome(self, s, t):
        n, m = len(s), len(t)
        best = 0
        subs_s = ['']
        for i in range(n):
            for j in range(i, n):
                subs_s.append(s[i:j + 1])
        subs_t = ['']
        for i in range(m):
            for j in range(i, m):
                subs_t.append(t[i:j + 1])
        for a in subs_s:
            for b in subs_t:
                if not a and not b:
                    continue
                c = a + b
                if c == c[::-1] and len(c) > best:
                    best = len(c)
        return best

