class Solution:
    def longestPalindrome(self, s, t):
        n, m = len(s), len(t)
        is_pal_s = [[False] * n for _ in range(n)]
        for i in range(n - 1, -1, -1):
            for j in range(i, n):
                if i == j:
                    is_pal_s[i][j] = True
                elif j == i + 1:
                    is_pal_s[i][j] = (s[i] == s[j])
                else:
                    is_pal_s[i][j] = (s[i] == s[j]) and is_pal_s[i + 1][j - 1]
        is_pal_t = [[False] * m for _ in range(m)]
        for i in range(m - 1, -1, -1):
            for j in range(i, m):
                if i == j:
                    is_pal_t[i][j] = True
                elif j == i + 1:
                    is_pal_t[i][j] = (t[i] == t[j])
                else:
                    is_pal_t[i][j] = (t[i] == t[j]) and is_pal_t[i + 1][j - 1]
        s_pref_pal = [0] * (n + 1)
        for x in range(n - 1, -1, -1):
            best_len = 1
            for j in range(n - 1, x - 1, -1):
                if is_pal_s[x][j]:
                    best_len = j - x + 1
                    break
            s_pref_pal[x] = best_len
        t_suf_pal = [0] * m
        for y in range(m):
            best_len = 1
            for i in range(0, y + 1):
                if is_pal_t[i][y]:
                    best_len = y - i + 1
                    break
            t_suf_pal[y] = best_len
        dp = [[0] * m for _ in range(n)]
        for i in range(n - 1, -1, -1):
            for j in range(m):
                if s[i] == t[j]:
                    nxt = dp[i + 1][j - 1] if (i + 1 < n and j - 1 >= 0) else 0
                    dp[i][j] = 1 + nxt
                else:
                    dp[i][j] = 0
        maxk = min(n, m)
        M = [max(dp[i]) for i in range(n)]
        N = [0] * m
        for j in range(m):
            best_col = 0
            for i in range(n):
                if dp[i][j] > best_col:
                    best_col = dp[i][j]
            N[j] = best_col
        NEG = -1
        best_s = [NEG] * (maxk + 1)
        for p in range(n):
            limit = M[p]
            for k in range(0, limit + 1):
                val = s_pref_pal[p + k] if p + k < n else 0
                if val > best_s[k]:
                    best_s[k] = val
        best_t = [NEG] * (maxk + 1)
        for v in range(m):
            limit = N[v]
            for k in range(0, limit + 1):
                idx = v - k
                val = t_suf_pal[idx] if idx >= 0 else 0
                if val > best_t[k]:
                    best_t[k] = val
        ans = 0
        for k in range(0, maxk + 1):
            best_ext = max(best_s[k], best_t[k])
            if best_ext < 0:
                continue
            if 2 * k + best_ext > ans:
                ans = 2 * k + best_ext
        return ans

