var longestPalindrome = function(s, t) {
    const n = s.length, m = t.length;
    const isPalS = Array.from({ length: n }, () => new Array(n).fill(false));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = i; j < n; j++) {
            if (i === j) isPalS[i][j] = true;
            else if (j === i + 1) isPalS[i][j] = (s[i] === s[j]);
            else isPalS[i][j] = (s[i] === s[j]) && isPalS[i + 1][j - 1];
        }
    }
    const isPalT = Array.from({ length: m }, () => new Array(m).fill(false));
    for (let i = m - 1; i >= 0; i--) {
        for (let j = i; j < m; j++) {
            if (i === j) isPalT[i][j] = true;
            else if (j === i + 1) isPalT[i][j] = (t[i] === t[j]);
            else isPalT[i][j] = (t[i] === t[j]) && isPalT[i + 1][j - 1];
        }
    }
    const sPrefPal = new Array(n + 1).fill(0);
    for (let x = n - 1; x >= 0; x--) {
        let bestLen = 1;
        for (let j = n - 1; j >= x; j--) {
            if (isPalS[x][j]) { bestLen = j - x + 1; break; }
        }
        sPrefPal[x] = bestLen;
    }
    const tSufPal = new Array(m).fill(0);
    for (let y = 0; y < m; y++) {
        let bestLen = 1;
        for (let i = 0; i <= y; i++) {
            if (isPalT[i][y]) { bestLen = y - i + 1; break; }
        }
        tSufPal[y] = bestLen;
    }
    const dp = Array.from({ length: n }, () => new Array(m).fill(0));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = 0; j < m; j++) {
            if (s[i] === t[j]) {
                const nxt = (i + 1 < n && j - 1 >= 0) ? dp[i + 1][j - 1] : 0;
                dp[i][j] = 1 + nxt;
            } else {
                dp[i][j] = 0;
            }
        }
    }
    const maxk = Math.min(n, m);
    const M = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let mx = 0;
        for (let j = 0; j < m; j++) if (dp[i][j] > mx) mx = dp[i][j];
        M[i] = mx;
    }
    const N = new Array(m).fill(0);
    for (let j = 0; j < m; j++) {
        let mx = 0;
        for (let i = 0; i < n; i++) if (dp[i][j] > mx) mx = dp[i][j];
        N[j] = mx;
    }
    const NEG = -1;
    const bestS = new Array(maxk + 1).fill(NEG);
    for (let p = 0; p < n; p++) {
        const limit = M[p];
        for (let k = 0; k <= limit; k++) {
            const val = (p + k < n) ? sPrefPal[p + k] : 0;
            if (val > bestS[k]) bestS[k] = val;
        }
    }
    const bestT = new Array(maxk + 1).fill(NEG);
    for (let v = 0; v < m; v++) {
        const limit = N[v];
        for (let k = 0; k <= limit; k++) {
            const idx = v - k;
            const val = (idx >= 0) ? tSufPal[idx] : 0;
            if (val > bestT[k]) bestT[k] = val;
        }
    }
    let ans = 0;
    for (let k = 0; k <= maxk; k++) {
        const bestExt = Math.max(bestS[k], bestT[k]);
        if (bestExt < 0) continue;
        if (2 * k + bestExt > ans) ans = 2 * k + bestExt;
    }
    return ans;
};
